import axios from "axios";
const apiURL = process.env.REACT_APP_API_URL;

export const cartListProduct = async () => {
  let carts = JSON.parse(localStorage.getItem("cart"));
  let productArray = [];
  if (carts) {
    for (const cart of carts) {
      productArray.push(cart.id);
    }
  }
  try {
    let res = await axios.post(`${apiURL}/api/product/cart-product`, {
      productArray,
    });
    return res.data;
  } catch (error) {
    console.log(error);
  }
};
export const getUserNotifications = async () => {
  let userId = JSON.parse(localStorage.getItem("jwt")).user._id;

  try {
    let res = await axios.post(`${apiURL}/api/notification/user-notifications`, {
      userId,
    });
    return res.data;
  } catch (error) {
    console.log(error);
  }
};

export const markNotificationRead = async (notificationId) => {
  try {
    let res = await axios.post(`${apiURL}/api/notification/mark-read`, {
      notificationId,
    });
    return res.data;
  } catch (error) {
    console.log(error);
  }
};
